UPDATE MENU_AUTH
   SET USE_YN      = 'N'
     , UPDATE_DATE = SYSDATE
     , UPWRITER_ID = #{upwriterId}
 WHERE DEPTNO = #{deptno}

mapper.insert:
MERGE INTO MENU_AUTH t USING (
SELECT #{deptno} AS DEPTNO , #{item.menuCode} AS MENU_CODE , #{item.menuNo} AS MENU_NO FROM dual
) s ON ( t.DEPTNO = s.DEPTNO AND t.MENU_CODE = s.MENU_CODE AND t.MENU_NO = s.MENU_NO) WHEN MATCHED THEN UPDATE SET t.USE_YN = 'Y' , t.UPDATE_DATE = SYSDATE , t.UPWRITER_ID = #{upwriterId} WHEN NOT MATCHED THEN INSERT (DEPTNO, MENU_CODE, MENU_NO, USE_YN, REGI_DATE, INWRITER_ID) VALUES (s.DEPTNO, s.MENU_CODE, s.MENU_NO, 'Y', SYSDATE, #{upwriterId})
